import { 運筆 } from '../bi.js';
import { 菩薩坐身 } from './pusa.js';
import { 法界定印, 臂釧 } from '../bujian/index.js';
// 五化佛冠（承薩埵 fugen-k 之制：冠帶綴珠，五化佛列坐，冠繒垂帶）
export function 五化佛冠(bi) {
    const { M, Qk, C, S, 衣, 細 } = 運筆(bi);
    const { dot, dim, A } = bi;
    衣(() => {
        M(-5.5, 8.9);
        Qk(0, 7.7, 5.5, 8.9);
        S();
        M(-5.35, 7.7);
        Qk(0, 6.5, 5.35, 7.7);
        S();
        細(() => { for (const [bx, bz] of [[-4.4, 8.15], [-2.2, 7.55], [0, 7.3], [2.2, 7.55], [4.4, 8.15]])
            dot(bx, bz, 0.2); });
        const 化佛 = (px, pz, s) => {
            細(() => {
                A(px, pz - 1.05 * s, 0.42 * s);
                M(px - 0.85 * s, pz + 0.75 * s);
                C(px - 0.9 * s, pz - 0.35 * s, px - 0.55 * s, pz - 0.55 * s, px, pz - 0.55 * s);
                C(px + 0.55 * s, pz - 0.55 * s, px + 0.9 * s, pz - 0.35 * s, px + 0.85 * s, pz + 0.75 * s);
                S();
                M(px - 0.85 * s, pz + 0.75 * s);
                Qk(px, pz + 0.95 * s, px + 0.85 * s, pz + 0.75 * s);
                S();
                dim(0.6, () => A(px, pz - 0.9 * s, 0.8 * s, Math.PI * 1.05, Math.PI * 1.95));
            });
        };
        化佛(0, 4.4, 1.0);
        化佛(-2.5, 5.0, 0.88);
        化佛(2.5, 5.0, 0.88);
        化佛(-4.7, 5.9, 0.78);
        化佛(4.7, 5.9, 0.78);
        for (const d of [-1, 1]) {
            dim(0.7, () => 細(() => {
                M(d * 5.8, 8.6);
                C(d * 7.9, 9.3, d * 8.3, 10.9, d * 8.9, 12.4);
                Qk(d * 9.25, 13.3, d * 8.7, 13.9);
                S();
            }));
        }
    });
}
export const 大日胎藏 = (bi) => 菩薩坐身(bi, {
    月輪: false,
    冠: 五化佛冠,
    臂(bi, 筆) {
        const { M, C, S, 骨, 陰, 陽 } = 筆;
        // 定印之臂（承彌陀之路）：肘外而前臂相就於腹前
        骨(() => {
            陽(() => {
                M(-13.4, 28.6);
                C(-14.6, 32.0, -15.2, 37.5, -15.0, 44.6);
                S();
                M(-15.0, 44.6);
                C(-13.4, 50.0, -9.5, 54.4, -5.6, 56.5);
                S();
                M(-10.9, 32.2);
                C(-11.6, 36.5, -12.0, 40.5, -11.9, 43.2);
                S();
                M(-11.9, 43.2);
                C(-10.5, 48.0, -7.8, 52.2, -4.6, 54.6);
                S();
            });
            陰(() => {
                M(13.4, 28.6);
                C(14.6, 32.0, 15.2, 37.5, 15.0, 44.6);
                S();
                M(15.0, 44.6);
                C(13.4, 50.0, 9.5, 54.4, 5.6, 56.5);
                S();
                M(10.9, 32.2);
                C(11.6, 36.5, 12.0, 40.5, 11.9, 43.2);
                S();
                M(11.9, 43.2);
                C(10.5, 48.0, 7.8, 52.2, 4.6, 54.6);
                S();
            });
        });
        法界定印(bi, 0, 57.8, 0.95, false);
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
    },
});
